final:
module RefModule(
    input clk,
    input en,
    input [15:0] d,
    input rst,
    output reg [15:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
begin
  if (rst)
    q <= 16'b0;
  else if (en)
    q <= d;
end

endmodule
